func compoundLaurelFiligreePath(outer string, islands []string) (*canvas.Path, error) {
	p, err := canvas.ParseSVGPath(outer)
	if err != nil {
		return nil, err
	}
	for _, s := range islands {
		q, err := canvas.ParseSVGPath(s)
		if err != nil {
			return nil, err
		}
		p = p.Append(q)
	}
	return p, nil
}

